910			mapName.nextToken(&token, "\\/");
911			// add all the tokens except the last one.
912			// that way we don't add the filename, just the
913			// directory name, we can do this since the filename
914			// is just the directory name with the file extention
915			// added onto it.
916			while (mapName.find('\\') != NULL)
917			{
918				if (newMapName.getLength() > 0)
919				{
920					newMapName.concat('/');
921				}
922				newMapName.concat(token);
923				mapName.nextToken(&token, "\\/");
924			}
925			DEBUG_LOG(("Map name is %s\n", mapName.str()));
926		}
927	
928		AsciiString optionsString;
929		optionsString.format("US=%d;M=%2.2x%s;MC=%X;MS=%d;SD=%d;C=%d;SR=%u;SC=%u;O=%c;", game->getUseStats(), game->getMapContentsMask(), newMapName.str(),
