from zh_copilot.replay.message_types import MsgType, ArgType
from pathlib import Path
from collections import defaultdict

general_ids: dict[str, set] = defaultdict(set)
files = sorted(Path('replays/dataset').glob('*.rep'))[:5000]
for f in files:
    try:
        rep = parse_replay_bytes(f.read_bytes())
        info = parse_game_options(rep.header.game_options)
