        for cmd in rep.commands:
            if cmd.frame > 1500:
                break
            if cmd.msg_type == MsgType.DOZER_CONSTRUCT:
                ints = cmd.args.get(ArgType.INTEGER, [])
                if ints:
                    slot = human_slots.get(cmd.player_idx)
                    if slot and slot.general not in ('Random', 'Observer', 'Unknown'):
                        general_ids[slot.general].add(ints[0])
    except:
        pass

all_ids = list(general_ids.items())
all_generals = list(general_ids.keys())

print('--- EXCLUSIVE IDs (appear in only ONE general) ---')
for gen in sorted(all_generals):
    others = set()
    for g2, ids2 in general_ids.items():
        if g2 != gen:
            others |= ids2
    exclusive = general_ids[gen] - others
    if exclusive:
        print(f'  {gen}: {sorted(exclusive)}')

print()
